// q6k_gemv.cu — custom in-kernel Q6_K dequant + GEMV for single-token decode.
//
// MODELED EXACTLY on q8_gemv.cu (the proven, correct kernel): SAME warp-per-rows
// mapping, SAME shared-x staging, SAME warp-shuffle reduce, SAME cubin
// build/load. ONLY the per-superblock dequant math differs (Q6_K superblock =
// 256 weights in 210 bytes, vs Q8_0's 32-element 34-byte block).
//
// WHY: Q4_K_M is MIXED — most tensors are Q4_K but ffn_down + attn_v are Q6_K.
// To keep the WHOLE mistral-7b decode in-kernel (partial residency is a measured
// catastrophe) BOTH the q4k and this q6k kernel are needed. ONE flag
// (MESH_GPU_Q4K) gates both.
//
// Q6_K superblock layout (matches dequantize_q6k_row in math.rs EXACTLY):
//   210 bytes per superblock of 256 weights:
//     bytes [0..128)   : ql — 128 bytes of 4-bit LOW quant bits (256 nibbles)
//     bytes [128..192) : qh —  64 bytes of 2-bit HIGH quant bits (256 crumbs)
//     bytes [192..208) : sc —  16 signed int8 per-sub-block scales
//     bytes [208..210) : f16 super-scale `d` (little-endian IEEE half)
//   q6 = (ql_nibble | (qh_crumb << 4)) - 32      (range -32..31)
//   weight = d * sc[sub] * q6
// A weight row of K elements is K/256 contiguous superblocks; the weight matrix
// is row-major [N rows × K], i.e. row r starts at byte offset r * (K/256) * 210.
//
//   out[r] = Σ_k dequant(W[r,k]) * x[k]   for r in [0, N)
//
// The CPU reference (math.rs::dequantize_q6k_row) processes each superblock as
// TWO groups of 128 outputs. For group g in {0,1} with ns = g*128:
//   qls = ql[g*64 .. g*64+64]   (64 low-nibble bytes)
//   qhs = qh[g*32 .. g*32+32]   (32 high-2bit bytes)
//   scs = sc[g*8  .. g*8+8]     (8 int8 scales)
//   for l in 0..32, is = l/16:
//     q1 = ((qls[l]    & 0xf) | (((qhs[l] >> 0) & 3) << 4)) - 32  → out[ns+l]      scale scs[is]
//     q2 = ((qls[l+32] & 0xf) | (((qhs[l] >> 2) & 3) << 4)) - 32  → out[ns+l+32]   scale scs[is+2]
//     q3 = ((qls[l]    >> 4)  | (((qhs[l] >> 4) & 3) << 4)) - 32  → out[ns+l+64]   scale scs[is+4]
//     q4 = ((qls[l+32] >> 4)  | (((qhs[l] >> 6) & 3) << 4)) - 32  → out[ns+l+96]   scale scs[is+6]
//     out[..] = d * scs[..] * q*   (signed int8 scale, signed q)
// We replicate that EXACT element→(ql byte, qh byte/shift, scale) mapping below
// and fold each weight against x immediately so the dequant is bit-identical.
//
// VECTORIZED / UNALIGNED-SAFE LOADS (same idioms as q8_gemv.cu): float4 x;
// the 210-byte superblock stride is not 16/4-aligned, so ql/qh/sc/d are copied
// into aligned locals via `__builtin_memcpy` of COMPILE-TIME-CONSTANT sizes
// (nvcc widens to the safest load; never a faulting over-aligned wide load).
// The 16 scales are read back through a SIGNED-char view (scales are int8).
//
// Build: compiled to a native sm_89 CUBIN at build time (build.rs nvcc --cubin
// -arch=sm_89); the cudarc DRIVER loads it (cuModuleLoadData) — no runtime NVRTC.

#include <cuda_fp16.h>

// MUST match Q4K_WARPS_PER_BLOCK / Q4K_ROWS_PER_WARP / Q4K_SHARED_X_MAX_K in
// cuda_matmul.rs (the q6k kernel shares the q4k launch constants).
#define WARPS_PER_BLOCK 8
#define ROWS_PER_WARP 2
// 16384 floats = 64 KB staged x (host opts into the sm_89 large-dynamic-shared
// limit via cuFuncSetAttribute). Raised 8192 -> 16384 so the gemma4-12b FFN
// down-proj (K=15360, Q6_K) stages x ONCE in shared instead of re-reading it
// from global per output row — ~236 MB/token of redundant x traffic removed,
// the dominant term in the ~158 ms down-matvec. MUST match Q4K_SHARED_X_MAX_K.
#define SHARED_X_MAX_K 16384

// Q6_K constants.
#define QK_K 256          // weights per superblock
#define Q6K_BLK_BYTES 210 // bytes per superblock

extern "C" __global__ void q6k_gemv(
    const unsigned char* __restrict__ W, // raw Q6_K bytes, row-major [N × K]
    const float* __restrict__ x,         // activation vector, length K
    float* __restrict__ out,             // output vector, length N
    int N,
    int K)
{
    const int warp_id = threadIdx.x >> 5;
    const int lane    = threadIdx.x & 31;

    const int sblk_per_row = K / QK_K;           // K / 256
    const size_t row_bytes = (size_t)sblk_per_row * Q6K_BLK_BYTES;

    // (A) Optional shared staging of x — IDENTICAL to q8_gemv.cu.
    extern __shared__ float xsh[];
    const bool use_shared = (K <= SHARED_X_MAX_K);
    if (use_shared) {
        for (int i = threadIdx.x; i < K; i += blockDim.x) {
            xsh[i] = __ldg(x + i);
        }
        __syncthreads();
    }

    // (B) This warp owns ROWS_PER_WARP rows starting at row0.
    const int warp_global = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const int row0        = warp_global * ROWS_PER_WARP;
    if (row0 >= N) return;

    float partial[ROWS_PER_WARP];
    #pragma unroll
    for (int r = 0; r < ROWS_PER_WARP; ++r) partial[r] = 0.0f;

    // Stride over the row's superblocks; each lane handles { lane, lane+32, … }.
    for (int sb = lane; sb < sblk_per_row; sb += 32) {
        const int xbase = sb * QK_K;             // first x index of this superblock
        const float* __restrict__ xsb =
            use_shared ? (const float*)(xsh + xbase) : (const float*)(x + xbase);
        // x for this superblock is now read from SHARED for the big-K down-proj
        // (SHARED_X_MAX_K raised to 16384 ≥ K=15360) — no DRAM cost, so the per-
        // row re-reads below are cheap shared loads, not redundant global traffic.
        // (Hoisting all 256 into registers would spill — 256 regs/thread — and
        // regress; shared reuse is the right lever here.)

        #pragma unroll
        for (int r = 0; r < ROWS_PER_WARP; ++r) {
            const int row = row0 + r;
            if (row >= N) continue;
            const unsigned char* __restrict__ bp =
                W + (size_t)row * row_bytes + (size_t)sb * Q6K_BLK_BYTES;

            // ql: 128 bytes [0..128). 16-byte-aligned local (int4[8]).
            union { int4 v[8]; unsigned char b[128]; } ql;
            __builtin_memcpy(&ql, bp, 128);
            // qh: 64 bytes [128..192). int4[4].
            union { int4 v[4]; unsigned char b[64]; } qh;
            __builtin_memcpy(&qh, bp + 128, 64);
            // sc: 16 SIGNED int8 scales [192..208). int4[1].
            union { int4 v[1]; signed char c[16]; } sc;
            __builtin_memcpy(&sc, bp + 192, 16);
            // f16 super-scale d [208..210), little-endian half.
            unsigned short raw_d;
            __builtin_memcpy(&raw_d, bp + 208, sizeof(unsigned short));
            const float d_val = __half2float(*reinterpret_cast<const __half*>(&raw_d));

            // Replicate dequantize_q6k_row's two groups of 128 outputs EXACTLY.
            float acc = 0.0f;
            #pragma unroll
            for (int group = 0; group < 2; ++group) {
                const int ns  = group * 128;     // output base within superblock
                const int qlo = group * 64;      // ql byte base
                const int qho = group * 32;      // qh byte base
                const int sco = group * 8;       // scale base
                // HOIST d*scale for this group's 8 sub-scales ONCE (was recomputed
                // 32x per element). Numerically identical: `d_val*s*q` reassociated
                // to `(d_val*s)*q` — same factors, same order.
                const float gs[8] = {
                    d_val * (float)sc.c[sco + 0], d_val * (float)sc.c[sco + 1],
                    d_val * (float)sc.c[sco + 2], d_val * (float)sc.c[sco + 3],
                    d_val * (float)sc.c[sco + 4], d_val * (float)sc.c[sco + 5],
                    d_val * (float)sc.c[sco + 6], d_val * (float)sc.c[sco + 7],
                };
                #pragma unroll
                for (int l = 0; l < 32; ++l) {
                    const int is = l >> 4;       // l / 16 (0 or 1)
                    const unsigned char qhl = qh.b[qho + l];
                    // q* = (low4 | (high2 << 4)) - 32, signed.
                    const int q1 = (int)((ql.b[qlo + l]      & 0xf) | (((qhl >> 0) & 3) << 4)) - 32;
                    const int q2 = (int)((ql.b[qlo + l + 32] & 0xf) | (((qhl >> 2) & 3) << 4)) - 32;
                    const int q3 = (int)((ql.b[qlo + l]      >> 4)  | (((qhl >> 4) & 3) << 4)) - 32;
                    const int q4 = (int)((ql.b[qlo + l + 32] >> 4)  | (((qhl >> 6) & 3) << 4)) - 32;
                    // scale indices is, is+2, is+4, is+6 within this group's 8.
                    acc += gs[is]     * (float)q1 * xsb[ns + l];
                    acc += gs[is + 2] * (float)q2 * xsb[ns + l + 32];
                    acc += gs[is + 4] * (float)q3 * xsb[ns + l + 64];
                    acc += gs[is + 6] * (float)q4 * xsb[ns + l + 96];
                }
            }
            partial[r] += acc;
        }
    }

    // Warp-shuffle reduction across the 32 lanes for each row → lane 0 writes.
    const unsigned FULL = 0xffffffffu;
    #pragma unroll
    for (int r = 0; r < ROWS_PER_WARP; ++r) {
        float p = partial[r];
        #pragma unroll
        for (int offset = 16; offset > 0; offset >>= 1) {
            p += __shfl_down_sync(FULL, p, offset);
        }
        const int row = row0 + r;
        if (lane == 0 && row < N) {
            out[row] = p;
        }
    }
}
